import { useState, useEffect, useRef } from "react";
import { toast } from "sonner";
import i18n from "@/i18n/config";

const CACHE_KEY = "user_geolocation";
const CACHE_TTL = 1000 * 60 * 30; // 30 minutes
const TOAST_SHOWN_KEY = "geolocation_toast_shown";
const TOAST_COOLDOWN = 1000 * 60 * 60; // 1 hour cooldown between toasts

interface CachedLocation {
  lat: number;
  lng: number;
  timestamp: number;
}

export interface UserGeolocation {
  lat: number | null;
  lng: number | null;
  isLoading: boolean;
  error: string | null;
}

const shouldShowToast = (): boolean => {
  try {
    const lastShown = localStorage.getItem(TOAST_SHOWN_KEY);
    if (lastShown && Date.now() - parseInt(lastShown) < TOAST_COOLDOWN) {
      return false;
    }
  } catch {}
  return true;
};

const markToastShown = () => {
  try {
    localStorage.setItem(TOAST_SHOWN_KEY, Date.now().toString());
  } catch {}
};

export const useUserGeolocation = (): UserGeolocation => {
  const toastShownRef = useRef(false);
  const [state, setState] = useState<UserGeolocation>(() => {
    try {
      const cached = localStorage.getItem(CACHE_KEY);
      if (cached) {
        const parsed: CachedLocation = JSON.parse(cached);
        if (Date.now() - parsed.timestamp < CACHE_TTL) {
          return { lat: parsed.lat, lng: parsed.lng, isLoading: false, error: null };
        }
      }
    } catch {}
    return { lat: null, lng: null, isLoading: true, error: null };
  });

  useEffect(() => {
    // Skip if cached
    try {
      const cached = localStorage.getItem(CACHE_KEY);
      if (cached) {
        const parsed: CachedLocation = JSON.parse(cached);
        if (Date.now() - parsed.timestamp < CACHE_TTL) {
          return;
        }
      }
    } catch {}

    if (!navigator?.geolocation) {
      setState(prev => ({ ...prev, isLoading: false, error: "not_supported" }));
      if (!toastShownRef.current && shouldShowToast()) {
        toastShownRef.current = true;
        markToastShown();
        toast.warning(i18n.t("common.locationNotSupported"), { duration: 6000 });
      }
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        const loc = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        localStorage.setItem(CACHE_KEY, JSON.stringify({
          ...loc,
          timestamp: Date.now(),
        }));
        setState({ ...loc, isLoading: false, error: null });
      },
      (err) => {
        console.warn("[useUserGeolocation] Failed:", err.message);
        setState(prev => ({ ...prev, isLoading: false, error: err.message }));
        
        if (!toastShownRef.current && shouldShowToast()) {
          toastShownRef.current = true;
          markToastShown();
          if (err.code === err.PERMISSION_DENIED) {
            toast.warning(i18n.t("common.locationDenied"), { duration: 6000 });
          } else {
            toast.warning(i18n.t("common.locationUnavailable"), { duration: 6000 });
          }
        }
      },
      { enableHighAccuracy: false, timeout: 10000, maximumAge: 300000 }
    );
  }, []);

  return state;
};
