import { useState, useEffect, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { BookOpen, Sparkles, Languages, Loader2, ThumbsUp } from "lucide-react";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";

interface StoryPopupDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  name: string;
  imageUrl?: string | null;
  photoStoryZh?: string | null;
  photoStoryEn?: string | null;
  photoStoryPt?: string | null;
  likesCount?: number;
}

/** Split text into building story + I Ching interpretation */
function splitStoryAndIChing(text: string) {
  // Look for I Ching markers
  const markers = ["《易经", "易经·", "易经解读", "【易经", "卦意", "综合卦意"];
  let ichingStart = -1;
  for (const marker of markers) {
    const idx = text.indexOf(marker);
    if (idx >= 0 && (ichingStart < 0 || idx < ichingStart)) {
      ichingStart = idx;
    }
  }

  if (ichingStart > 0) {
    // Walk back to the nearest paragraph break
    const breakIdx = text.lastIndexOf("\n", ichingStart);
    const cutPoint = breakIdx > 0 ? breakIdx : ichingStart;
    return {
      story: text.slice(0, cutPoint).trim(),
      iching: text.slice(cutPoint).trim(),
    };
  }
  return { story: text, iching: "" };
}

const StoryPopupDialog = ({
  open,
  onOpenChange,
  name,
  imageUrl,
  photoStoryZh,
  photoStoryEn,
  photoStoryPt,
  likesCount,
}: StoryPopupDialogProps) => {
  const { t, i18n } = useTranslation();
  const lang = i18n.language;

  // Get the story text with language fallback
  const rawStory = useMemo(() => {
    if (lang === "zh") return photoStoryZh || "";
    if (lang === "en") return photoStoryEn || photoStoryZh || "";
    if (lang === "pt") return photoStoryPt || photoStoryZh || "";
    return photoStoryZh || "";
  }, [lang, photoStoryZh, photoStoryEn, photoStoryPt]);

  // Auto-translate story for non-core languages
  const [translatedStory, setTranslatedStory] = useState<string | null>(null);
  const [isAutoTranslating, setIsAutoTranslating] = useState(false);

  // I Ching always shows Chinese, with manual translate
  const [ichingTranslated, setIchingTranslated] = useState<string | null>(null);
  const [isTranslatingIChing, setIsTranslatingIChing] = useState(false);

  const { story: storyPart, iching: ichingPart } = useMemo(
    () => splitStoryAndIChing(photoStoryZh || ""),
    [photoStoryZh]
  );

  // Auto-translate story part when not core language
  useEffect(() => {
    if (!open || !storyPart || lang === "zh") return;
    // For en/pt, check if we already have a DB translation
    if (lang === "en" && photoStoryEn) {
      const { story } = splitStoryAndIChing(photoStoryEn);
      if (story) { setTranslatedStory(story); return; }
    }
    if (lang === "pt" && photoStoryPt) {
      const { story } = splitStoryAndIChing(photoStoryPt);
      if (story) { setTranslatedStory(story); return; }
    }

    setIsAutoTranslating(true);
    supabase.functions
      .invoke("translate-content", { body: { text: storyPart, targetLang: lang } })
      .then(({ data, error }) => {
        if (!error && data?.translatedText) {
          setTranslatedStory(data.translatedText);
        }
      })
      .finally(() => setIsAutoTranslating(false));
  }, [open, storyPart, lang, photoStoryEn, photoStoryPt]);

  // Reset on close
  useEffect(() => {
    if (!open) {
      setTranslatedStory(null);
      setIchingTranslated(null);
    }
  }, [open]);

  const handleTranslateIChing = async () => {
    if (!ichingPart || isTranslatingIChing) return;
    setIsTranslatingIChing(true);
    try {
      const { data, error } = await supabase.functions.invoke("translate-content", {
        body: { text: ichingPart, targetLang: lang },
      });
      if (!error && data?.translatedText) {
        setIchingTranslated(data.translatedText);
      }
    } finally {
      setIsTranslatingIChing(false);
    }
  };

  const displayStory = lang === "zh" ? storyPart : (translatedStory || storyPart);
  const displayIChing = ichingTranslated || ichingPart;

  if (!photoStoryZh) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md p-0 overflow-hidden gap-0 [&>button]:bg-primary/85 [&>button]:backdrop-blur-md [&>button]:text-primary-foreground [&>button]:rounded-full [&>button]:border [&>button]:border-white/20 [&>button]:shadow-[0_2px_8px_rgba(0,0,0,0.3),inset_0_1px_0_rgba(255,255,255,0.15)] [&>button]:hover:bg-primary [&>button]:hover:scale-105 [&>button]:transition-all [&>button]:duration-200 [&>button]:w-7 [&>button]:h-7 [&>button]:top-3 [&>button]:right-3 [&>button]:opacity-100 [&>button]:flex [&>button]:items-center [&>button]:justify-center [&>button>svg]:w-3.5 [&>button>svg]:h-3.5">
        {/* Hero image */}
        {imageUrl && (
          <div className="relative h-48 w-full overflow-hidden">
            <img
              src={imageUrl}
              alt={name}
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
            <div className="absolute bottom-3 left-4 right-4">
              <div className="flex items-center gap-2 text-white/90 text-xs mb-1">
                <BookOpen className="w-4 h-4" />
                <span>{t("restaurants.buildingStory", "故事")}</span>
                {likesCount != null && likesCount > 0 && (
                  <span className="flex items-center gap-0.5 ml-2">
                    <ThumbsUp className="w-3 h-3" /> {likesCount}
                  </span>
                )}
              </div>
              <h3 className="text-white font-semibold text-base leading-tight">{name}</h3>
            </div>
          </div>
        )}

        <div className="p-4 space-y-4 max-h-[60vh] overflow-y-auto">
          {/* Building Story — auto translated */}
          {displayStory && (
            <div className="text-sm text-foreground/90 leading-relaxed">
              {isAutoTranslating ? (
                <div className="flex items-center gap-2 text-muted-foreground py-2">
                  <Loader2 className="w-4 h-4 animate-spin" />
                  {t("common.loading")}
                </div>
              ) : (
                <p className="whitespace-pre-line">{displayStory}</p>
              )}
            </div>
          )}

          {/* I Ching Section — Chinese by default, with translate button */}
          {ichingPart && (
            <div className="bg-muted/50 rounded-lg p-3 border border-border/50">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-1.5 text-sm font-semibold text-foreground">
                  <Sparkles className="w-4 h-4 text-primary" />
                  {t("restaurant.iching", "易经解读")}
                </div>
                {lang !== "zh" && (
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-7 px-2 text-xs gap-1"
                    onClick={() => {
                      if (ichingTranslated) {
                        setIchingTranslated(null);
                      } else {
                        handleTranslateIChing();
                      }
                    }}
                    disabled={isTranslatingIChing}
                  >
                    {isTranslatingIChing ? (
                      <Loader2 className="w-3 h-3 animate-spin" />
                    ) : (
                      <Languages className="w-3 h-3" />
                    )}
                    {ichingTranslated
                      ? t("translate.showOriginal")
                      : t("translate.button")}
                  </Button>
                )}
              </div>
              <p className="text-sm text-foreground/80 whitespace-pre-line leading-relaxed">
                {ichingTranslated || ichingPart}
              </p>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default StoryPopupDialog;
